import { useState, useEffect } from "react";
import axios from "axios";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function Projectdetails() {

const [showForm, setShowForm] = useState(false);
const [projects, setProjects] = useState([]);
const [editId, setEditId] = useState(null);

const [formData, setFormData] = useState({
name:"",
location:"",
budget:"",
minBudget:"",
maxBudget:"",
floors:"",
area:"",
parking:"",
amenities:"",
start_date:"",
end_date:"",
duration:"",
description:"",
status:"Active"
});

useEffect(()=>{
fetchProjects();
},[]);

const fetchProjects = async ()=>{
try{
const res = await axios.get("http://localhost:5000/api/projects");
setProjects(res.data);
}catch(err){
console.error(err);
}
};

// HANDLE INPUT
const handleChange = (e)=>{
const {name,value} = e.target;

// LIVE BLOCK INVALID INPUT
if (name === "name" && !/^[A-Za-z ]*$/.test(value)) return;
if (name === "location" && !/^[A-Za-z ]*$/.test(value)) return;

let updated = { ...formData, [name]: value };

// AUTO DURATION
if(name==="start_date" || name==="end_date"){
const start = name==="start_date" ? value : formData.start_date;
const end = name==="end_date" ? value : formData.end_date;

if(start && end){
const years =
(new Date(end) - new Date(start)) /
(1000 * 60 * 60 * 24 * 365);

updated.duration = years.toFixed(2);
}
}

setFormData(updated);
};

// VALIDATION
const validateForm = () => {

if (!/^[A-Za-z ]+$/.test(formData.name)) {
alert("Project name must contain only alphabets");
return false;
}

if (!/^[A-Za-z ]+$/.test(formData.location)) {
alert("Location must contain only alphabets");
return false;
}

if (!formData.start_date || !formData.end_date) {
alert("Start and End date required");
return false;
}

const start = new Date(formData.start_date);
const end = new Date(formData.end_date);

if (start >= end) {
alert("Start date must be before End date");
return false;
}

const duration = (end - start) / (1000 * 60 * 60 * 24 * 365);

if (duration < 2 || duration > 5) {
alert("Duration must be 2–5 years");
return false;
}

if (formData.minBudget && formData.maxBudget) {
if (Number(formData.minBudget) >= Number(formData.maxBudget)) {
alert("Min budget must be less than Max");
return false;
}
}

if (!formData.floors || formData.floors <= 0) {
alert("Floors must be greater than 0");
return false;
}

return true;
};

// SUBMIT
const handleSubmit = async ()=>{

if(!validateForm()) return;

try{

const payload = {
...formData,
budget: formData.budget || formData.maxBudget
};

if(editId){
await axios.put(`http://localhost:5000/api/projects/${editId}`, payload);
}else{
await axios.post("http://localhost:5000/api/projects/add", payload);
}

fetchProjects();

setFormData({
name:"",
location:"",
budget:"",
minBudget:"",
maxBudget:"",
floors:"",
area:"",
parking:"",
amenities:"",
start_date:"",
end_date:"",
duration:"",
description:"",
status:"Active"
});

setEditId(null);
setShowForm(false);

}catch(err){
console.error(err);
alert("Error saving project");
}
};

// EDIT
const handleEdit = (project)=>{
setFormData({
name:project.name,
location:project.location,
budget:project.budget || "",
minBudget:project.min_budget || "",
maxBudget:project.max_budget || "",
floors:project.floors,
area:project.area || "",
parking:project.parking || "",
amenities:project.amenities || "",
start_date:project.start_date,
end_date:project.end_date,
duration:project.duration || "",
description:project.description,
status:project.status
});
setEditId(project.id);
setShowForm(true);
};

// VIEW
const handleView = (project)=>{
alert(JSON.stringify(project,null,2));
};

return(

<div className="flex bg-gray-100 min-h-screen">

<Sidebar/>

<div className="flex-1 flex flex-col">

<Topbar/>

<div className="p-8">

{!showForm && (

<>

<div className="flex justify-between items-center mb-6">
<div>
<h1 className="text-3xl font-bold">Project Details</h1>
<p className="text-gray-500">Manage all construction projects</p>
</div>

<button onClick={()=>setShowForm(true)} className="bg-orange-500 text-white px-6 py-3 rounded-xl">

* Add Project

  </button>

</div>

<div className="grid grid-cols-3 gap-6">

{projects.map((project)=>(

<div key={project.id} className="bg-white p-6 rounded-2xl shadow relative">

<div className="absolute top-4 right-4 flex gap-3">
<button onClick={()=>handleEdit(project)}>✏️</button>
<button onClick={()=>handleView(project)}>👁️</button>
</div>

<h3 className="text-xl font-bold">{project.name}</h3>
<p>📍 {project.location}</p>
<p>💰 ₹{project.budget}</p>
<p>🏢 Floors: {project.floors}</p>
<p>🚗 Parking: {project.parking}</p>
<p>🛠 Amenities: {project.amenities}</p>
<p>📅 {project.start_date} → {project.end_date}</p>
<p>⏳ {project.duration} yrs</p>

<span className="bg-green-100 px-3 py-1 rounded">
{project.status}
</span>

</div>

))}

</div>
</>
)}

{showForm && (

<div className="bg-white p-8 rounded-2xl shadow">

<h2 className="text-2xl font-semibold mb-6">
{editId ? "Edit Project" : "Add Project"}
</h2>

<div className="grid grid-cols-2 gap-6">

<div>
<label>Project Name</label>
<input name="name" value={formData.name} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>Location</label>
<input name="location" value={formData.location} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>Min Budget</label>
<input type="number" name="minBudget" value={formData.minBudget} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>Max Budget</label>
<input type="number" name="maxBudget" value={formData.maxBudget} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>Floors</label>
<input type="number" name="floors" value={formData.floors} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>Area</label>
<input type="number" name="area" value={formData.area} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>Parking</label>
<select name="parking" value={formData.parking} onChange={handleChange} className="border p-3 rounded-xl w-full">
<option value="">Select</option>
<option value="0">No Parking</option>
<option value="10">10</option>
<option value="20">20</option>
</select>
</div>

<div>
<label>Amenities</label>
<input name="amenities" value={formData.amenities} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>Start Date</label>
<input type="date" name="start_date" value={formData.start_date} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

<div>
<label>End Date</label>
<input type="date" name="end_date" value={formData.end_date} onChange={handleChange} className="border p-3 rounded-xl w-full"/>
</div>

</div>

<p className="mt-3 text-sm">
Duration: {formData.duration || 0} yrs
</p>

<select name="status" value={formData.status} onChange={handleChange} className="border p-3 rounded-xl w-full mt-3">
<option>Active</option>
<option>Completed</option>
<option>On Hold</option>
</select>

<div className="flex gap-4 mt-6">

<button onClick={handleSubmit} className="bg-orange-500 text-white px-6 py-3 rounded-xl">
Save
</button>

<button onClick={()=>setShowForm(false)} className="bg-gray-300 px-6 py-3 rounded-xl">
Cancel </button>

</div>

</div>

)}

</div>

</div>

</div>

);

}
